// ── Nova Hierarquia de Usuários ──────────────────────────────────
// Níveis: 0=administrador(dono) > 1=gerente > 2=supervisor > 3=operador
const ROLE_HIERARCHY = {
  administrador: 0,
  gerente:        1,
  supervisor:     2,
  operador:       3,
  // aliases legados — mapeados internamente
  mestre:         0,
  master:         1,
  indicado:       3,
  visitante:      3,
  digitador:      3,
};
